IMAGE_EXAMPLE = ''

def color_plt_to_tk(color_name):
    try:
        rgba = mcolors.to_rgba(color_name)
        rgb_255 = tuple(int(c * 255) for c in rgba[:3])
        return True, f'#{rgb_255[0]:02x}{rgb_255[1]:02x}{rgb_255[2]:02x}'
    except ValueError:
        return False, 'red'

def validate_float(new_value):
    if new_value == "" or new_value == "-" or new_value == ".":
        return True
    try:
        float(new_value)
        return True
    except ValueError:
        return False

def inverse_color(color_name):
    rgba = mcolors.to_rgba(color_name)
    rgb_255 = tuple((255 - int(c * 255)) for c in rgba[:3])
    return f'#{rgb_255[0]:02x}{rgb_255[1]:02x}{rgb_255[2]:02x}'

def get_embedded_image(image_data):
    try:
        img_bytes = base64.b64decode(image_data)
        img_io = io.BytesIO(img_bytes)
        img = Image.open(img_io)
        return img
    except:
        return None

class Func:

    def __init__(self, index):

        self.index = index
        self.line = None
        self.func_name = 'f(x)'

        self.frame = ttk.Frame(entry_frame, relief='groove')
        self.frame.pack(fill='x', pady=5)

        self.label = ttk.Label(self.frame, text=self.func_name+'=', font=label_font)
        self.label.grid(row=0, column=0, padx=(5,0), pady=(6,3), sticky='w')

        self.entry = ttk.Entry(self.frame, width=entry_width, font=entry_font)
        self.entry.grid(row=0, column=1, columnspan=25, pady=(6,3), sticky='w', ipady=entry_height)

        self.limited = tk.BooleanVar(value=True)
        self.limited_button = ttk.Checkbutton(self.frame, text='limit', width=5, variable=self.limited, command=self.limited_check)
        self.limited_button.grid(row=1, column=0, padx=(6,2), pady=3, sticky='w')

        self.x_min_spin = ttk.Spinbox(self.frame, from_=x_min, to=x_max, increment=x_step, validate='key', validatecommand=(vcmd, '%P'), width=spin_width, font=spin_font, state='disabled')
        self.x_min_spin.set(x_min)
        self.x_min_spin.grid(row=1, column=1, padx=2, pady=3, sticky='w')

        self.x_max_spin = ttk.Spinbox(self.frame, from_=x_min, to=x_max, increment=x_step, validate='key', validatecommand=(vcmd, '%P'),  width=spin_width, font=spin_font, state='disabled')
        self.x_max_spin.set(x_max)
        self.x_max_spin.grid(row=1, column=2, padx=2, pady=3, sticky='w')

        self.n_points_spin = ttk.Spinbox(self.frame, from_=100, to=1000000, increment=n_step, validate='key', validatecommand=(vcmd, '%P'), width=2*spin_width, font=spin_font, state='disabled')
        self.n_points_spin.set(n_points)
        self.n_points_spin.grid(row=1, column=3, columnspan=2, padx=2, pady=3, sticky='w')

        self.delete_button = ttk.Button(self.frame, text='delete', width=button_width, command=self.delete)
        self.delete_button.grid(row=2, column=0, padx=(6,2), pady=(2,6), sticky='w', ipady=button_height)

        self.draw_button = ttk.Button(self.frame, text='draw', width=button_width, command=self.draw)
        self.draw_button.grid(row=2, column=1, padx=2, pady=(2,6), sticky='w', ipady=button_height)

        self.line_combo = ttk.Combobox(self.frame, values=line_styles, width=button_width, state='readonly')
        self.line_combo.set('solid')
        self.line_combo.grid(row=2, column=2, padx=2, pady=(2,6), sticky='w', ipady=button_height)

        self.color_combo = ttk.Combobox(self.frame, values=color_styles, width=button_width)
        self.color_combo.set('red')
        self.color_combo.grid(row=2, column=3, padx=2, pady=(2,6), sticky='w', ipady=button_height)

        self.color_preview = tk.Label(self.frame, width=2, bg=self.color_combo.get())
        self.color_preview.grid(row=2, column=4, padx=2, pady=(2,6), sticky='w')

        self.color_combo.bind('<<ComboboxSelected>>', self.update_color_preview)
        self.color_combo.bind('<KeyRelease>', self.update_color_preview)

    def limited_check(self):

        if self.limited.get():
            self.x_min_spin.config(state='disabled')
            self.x_max_spin.config(state='disabled')
            self.n_points_spin.config(state='disabled')
        else:
            self.x_min_spin.config(state='normal')
            self.x_max_spin.config(state='normal')
            self.n_points_spin.config(state='normal')

    def update_color_preview(self, event):
        color_name = self.color_combo.get().strip()
        tk_color = color_plt_to_tk(color_name)
        if tk_color[0]:
            self.color_preview.config(bg=tk_color[1])

    def clear(self):

        tfe.func_del_s(self.func_name)
        if self.line:
            self.line[0].remove()
            self.line = None
        self.frame.destroy()
        canvas.draw_idle()

    def delete(self):
        self.clear()
        FuncManager.deleteFunc(self.index)

    def update(self):
        self.x_min_spin.configure(from_=x_min, to=x_max, increment=x_step)
        self.x_max_spin.configure(from_=x_min, to=x_max, increment=x_step)
        self.n_points_spin.configure(increment=n_step)
        self.draw()

    def draw(self):
        if self.line:
            self.line[0].remove()
            self.line = None

        func_str = self.entry.get()
        if func_str.count('=') == 1:
            func_name, func_str = func_str.split('=')
            func_name = func_name.strip()
            if func_name == 'f(x)':
                tfe.func_del_s(self.func_name)
                self.func_name = func_name
                self.label.config(text=self.func_name+'=')
                if not func_str.strip():
                    canvas.draw_idle()
                    self.entry.configure(foreground='black')
                    return
                res, f = tfe.func_eval_s(func_str, param_names)
            else:
                if not func_str.strip():
                    canvas.draw_idle()
                    self.entry.configure(foreground='black')
                    return
                if 1 <= len(func_name) <= 4 and func_name.isalnum() and func_name.isascii() and tfe.func_name_free_s(func_name):
                    if self.func_name != func_name:
                        tfe.func_del_s(self.func_name)
                    self.func_name = func_name
                    self.label.config(text=self.func_name+'=')
                    res, f = tfe.func_add_s(func_str, param_names, func_name)
                else:
                    if self.func_name == 'f(x)':
                        res, f = tfe.func_eval_s(func_str, param_names)
                    else:
                        res, f = tfe.func_add_s(func_str, param_names, self.func_name)
                    self.entry.configure(foreground='blue')
        else:
            if not func_str.strip():
                canvas.draw_idle()
                self.entry.configure(foreground='black')
                return
            if self.func_name == 'f(x)':
                res, f = tfe.func_eval_s(func_str, param_names)
            else:
                res, f = tfe.func_add_s(func_str, param_names, self.func_name)
       
        if res == 'fail':
            self.entry.configure(foreground='red')
            return

        x = np.linspace(x_min, x_max, n_points)
        if not self.limited.get():
            try:
                local_x_min = max(x_min, min(x_max, float(self.x_min_spin.get())))
                self.x_min_spin.set(local_x_min)
                local_x_max = min(x_max, max(x_min, float(self.x_max_spin.get())))
                self.x_max_spin.set(local_x_max)
                local_n_points = min(1000000, max(100, int(self.n_points_spin.get())))
                self.n_points_spin.set(local_n_points)
                x = np.linspace(local_x_min, local_x_max, local_n_points)
            except ValueError:
                pass
        
        color_name = self.color_combo.get()
        tk_color = color_plt_to_tk(color_name)
        if tk_color[0]:
            color_name = tk_color[1]
        else:
            color_name = 'red'

        try:
            if res == 'num':
                self.line = ax.plot(x, np.full_like(x, f), linestyle=self.line_combo.get(), color=color_name, linewidth=line_width)
            if res == 'func':
                self.line = ax.plot(x, f(x), linestyle=self.line_combo.get(), color=color_name, linewidth=line_width)
            canvas.draw_idle()
            self.entry.configure(foreground='black')
        except:
            self.entry.configure(foreground='red')

class FuncManager:
    funcs = {}
    func_cnt = 0

    @staticmethod
    def addFunc():

        FuncManager.func_cnt += 1
        index = FuncManager.func_cnt

        func = Func(index)

        FuncManager.funcs[index] = func

    @staticmethod
    def drawFunc(index):

        FuncManager.funcs[index].draw()

    @staticmethod
    def drawAllFuncs():

        for func in FuncManager.funcs.values():
            func.draw()

    @staticmethod
    def deleteFunc(index):

        del FuncManager.funcs[index]

    @staticmethod
    def clearFuncs():

        for func in FuncManager.funcs.values():
            func.clear()
        FuncManager.funcs.clear()

    @staticmethod
    def updateFuncs():

        for func in FuncManager.funcs.values():
            func.update()

    @staticmethod
    def clearLines():

        for func in FuncManager.funcs.values():
            func.line = None

def drawAxis():
    global ax

    FuncManager.clearLines()
    fig.clear()

    axis_type = type_combo.get()
    axis_line = axis_line_combo.get()

    if axis_type == 'polar':

        ax = fig.add_subplot(111, projection='polar')

        color_name = color_combo.get()
        ax.set_facecolor(color_name)
        fig.patch.set_facecolor(color_name)

        ax.set_rlim(0, np.abs(y_max))
        ax.set_thetalim(0, 2*np.pi)
        ax.set_autoscale_on(False)

        y_scale = scale_dict[y_scale_combo.get()]
        if type(y_scale) != str:
            ax.set_yscale('function', functions=y_scale)
        else:
            try:
                n = float(y_scale_spin.get())
            except:
                n = 2.0
            finally:
                n = min(10.0, max(0.1, n))
                y_scale_spin.set(n)
            match y_scale:
                case 'linear':
                    ax.set_yscale('linear')
                case 'symlog':
                    ax.set_yscale('symlog')
                case 'nx':
                    ax.set_yscale('function', functions=(lambda x: x * n, lambda x: x / n))
                case 'pown':
                    ax.set_yscale('function', functions=(lambda x: np.pow(np.abs(x), n) * np.sign(x), lambda x: np.pow(np.abs(x), 1/n) * np.sign(x)))
                case 'expn':
                    ax.set_yscale('function', functions=(lambda x: np.pow(n, x), lambda x: np.emath.logn(n, x)))
                case 'log1pn':
                    ax.set_yscale('function', functions=(lambda x: np.log1p(np.abs(x)) / np.log(n) * np.sign(x), lambda x: sc.powm1(n, x)))

        if axis_line == 'none':
            ax.set_axis_off()
        else:

            inverse_color_name = inverse_color(color_name)

            ax.spines['polar'].set_color(inverse_color_name)

            ax.set_xticks(np.arange(0, 2*np.pi, np.pi/4))
            ax.set_xticklabels(theta_ticks)
            ax.set_yticks(np.arange(0, np.abs(y_max), y_step))
            ax.tick_params(axis='both', colors=inverse_color_name)

            ax.grid(True, linestyle=axis_line, alpha=0.3, color=inverse_color_name)

    else:
        
        ax = fig.add_subplot(111)

        color_name = color_combo.get()
        ax.set_facecolor(color_name)
        fig.patch.set_facecolor(color_name)

        ax.spines['top'].set_visible(False)
        ax.spines['right'].set_visible(False)
        ax.spines['bottom'].set_position('zero')
        ax.spines['left'].set_position('zero')

        ax.set_xlim(x_min, x_max)
        ax.set_ylim(y_min, y_max)
        
        if axis_type == 'equal':
            ax.set_aspect('equal')

        x_scale = scale_dict[x_scale_combo.get()]
        if type(x_scale) != str:
            ax.set_xscale('function', functions=x_scale)
        else:
            try:
                n = float(x_scale_spin.get())
            except:
                n = 2.0
            finally:
                n = min(10.0, max(0.1, n))
                x_scale_spin.set(n)
            match x_scale:
                case 'linear':
                    ax.set_xscale('linear')
                case 'symlog':
                    ax.set_xscale('symlog')
                case 'nx':
                    ax.set_xscale('function', functions=(lambda x: x * n, lambda x: x / n))
                case 'pown':
                    ax.set_xscale('function', functions=(lambda x: np.pow(np.abs(x), n) * np.sign(x), lambda x: np.pow(np.abs(x), 1/n) * np.sign(x)))
                case 'expn':
                    ax.set_xscale('function', functions=(lambda x: np.pow(n, x), lambda x: np.log(n, x)))
                case 'log1pn':
                    ax.set_xscale('function', functions=(lambda x: np.log1p(np.abs(x)) / np.log(n) * np.sign(x), lambda x: sc.powm1(n, x)))

        y_scale = scale_dict[y_scale_combo.get()]
        if type(y_scale) != str:
            ax.set_yscale('function', functions=y_scale)
        else:
            try:
                n = float(y_scale_spin.get())
            except:
                n = 2.0
            finally:
                n = min(10.0, max(0.1, n))
                y_scale_spin.set(n)
            match y_scale:
                case 'linear':
                    ax.set_yscale('linear')
                case 'symlog':
                    ax.set_yscale('symlog')
                case 'nx':
                    ax.set_yscale('function', functions=(lambda x: x * n, lambda x: x / n))
                case 'pown':
                    ax.set_yscale('function', functions=(lambda x: np.pow(np.abs(x), n) * np.sign(x), lambda x: np.pow(np.abs(x), 1/n) * np.sign(x)))
                case 'expn':
                    ax.set_yscale('function', functions=(lambda x: np.pow(n, x), lambda x: np.emath.logn(n, x)))
                case 'log1pn':
                    ax.set_yscale('function', functions=(lambda x: np.log1p(np.abs(x)) / np.log(n) * np.sign(x), lambda x: sc.powm1(n, x)))

        inverse_color_name = inverse_color(color_name)

        if axis_line == 'none':
            ax.set_axis_off()
        else:

            ax.spines['bottom'].set_color(inverse_color_name)
            ax.spines['left'].set_color(inverse_color_name)
            
            ax.set_xticks(np.arange(x_min, x_max, x_step))
            ax.set_yticks(np.arange(y_min, y_max, y_step))
            ax.tick_params(axis='both', colors=inverse_color_name)

            ax.grid(True, alpha=0.3, color=inverse_color_name)

    canvas.draw()

def updateAxis():
    global x_min, x_max, x_step, y_min, y_max, y_step, n_points, n_step

    try:
        x_min = min(1e6, max(-1e6, float(x_min_spin.get())))
        x_max = min(1e6, max(-1e6, float(x_max_spin.get())))
        x_step = max((x_max-x_min)//20, min(1e5, max(1e-6, float(x_step_combo.get()))))
        y_min = min(1e6, max(-1e6, float(y_min_spin.get())))
        y_max = min(1e6, max(-1e6, float(y_max_spin.get())))
        y_step = max((y_max-y_min)//20, min(1e5, max(1e-6, float(y_step_combo.get()))))
        n_points = min(1000000, max(1000, int(n_points_spin.get())))
        n_step = min(100000, max(100, int(n_step_combo.get())))
    except ValueError:
        return
    
    x_min_spin.set(x_min)
    x_max_spin.set(x_max)
    x_step_combo.set(x_step)
    y_min_spin.set(y_min)
    y_max_spin.set(y_max)
    y_step_combo.set(y_step)
    n_points_spin.set(n_points)
    n_step_combo.set(n_step)

    x_min_spin.configure(increment=x_step)
    x_max_spin.configure(increment=x_step)
    n_points_spin.configure(increment=n_step)

    drawAxis()
    FuncManager.updateFuncs()

def saveFigure():
    from tkinter import filedialog

    path = filedialog.asksaveasfilename(
        defaultextension=".jpg",
        filetypes=[
            ("JPEG Image", "*.jpg *.jpeg"),
            ("PNG Image", "*.png"),
            ("PDF Document", "*.pdf"),
            ("SVG Vector", "*.svg")
        ]
    )
    if path:
        ax.figure.savefig(path, dpi=600, bbox_inches='tight')

