def on_entry_frame_configure(event):
    entry_canvas.configure(scrollregion=entry_canvas.bbox('all'))
    entry_canvas.itemconfig(entry_window, width=event.width)
entry_frame.bind('<Configure>', on_entry_frame_configure)

def on_entry_wheel(event):
    entry_canvas.yview_scroll(int(-1*(event.delta/120)), 'units')
entry_canvas.bind('<MouseWheel>', on_entry_wheel)

def bubble_wheel(event):
    widget = event.widget
    if hasattr(widget, 'bind'):
        if widget.bind('<MouseWheel>') or hasattr(widget, 'yview') or hasattr(widget, 'xview'):
            return 'break'
    else:
        return 'break'
    parent = widget.master
    if parent:
        parent.event_generate('<MouseWheel>', delta=event.delta)
    return 'break'
root.bind_all('<MouseWheel>', bubble_wheel, add='+')

