axis_frame.pack(fill='x', anchor='w')

face_label = ttk.Label(axis_frame, text='color:', font=limit_font)
face_label.pack(side='left', padx=(10,0), pady=5)

color_combo = ttk.Combobox(axis_frame, values=color_styles, width=button_width, state='readonly', font=limit_font)
color_combo.set('white')
color_combo.pack(side='left', pady=5)

color_preview = tk.Label(axis_frame, width=2, bg=color_combo.get())
color_preview.pack(side='left', padx=5, pady=5)

def update_color_preview(event):
    color_preview.config(bg=color_combo.get())
color_combo.bind('<<ComboboxSelected>>', update_color_preview)

type_label = ttk.Label(axis_frame, text='type:', font=limit_font)
type_label.pack(side='left', padx=(20,0), pady=5)

type_combo = ttk.Combobox(axis_frame, values=axis_types, width=button_width, state='readonly', font=limit_font)
type_combo.set('normal')
type_combo.pack(side='left', pady=5)

axis_line_label = ttk.Label(axis_frame, text="lines:", font=limit_font)
axis_line_label.pack(side='left', padx=(20,0), pady=5)

axis_line_combo = ttk.Combobox(axis_frame, values=axis_line_styles, width=limit_width, font=limit_font, state='readonly')
axis_line_combo.set('solid')
axis_line_combo.pack(side='left', pady=5)

update_button = ttk.Button(axis_frame, style='Limit.TButton', text="update", width=limit_width, command=updateAxis)
update_button.pack(side='left', padx=(30,15), pady=5)

save_button = ttk.Button(axis_frame, style='Limit.TButton', text="save", width=limit_width, command=saveFigure)
save_button.pack(side='left', padx=15, pady=5)

help_button = ttk.Button(axis_frame, style='Limit.TButton', text="help", width=limit_width, command=giveHelp)
help_button.pack(side='left', padx=15, pady=5)

draw_frame = ttk.Frame(right_frame)
draw_frame.pack(fill='both', expand=True)

fig = plt.figure()

canvas = FigureCanvasTkAgg(fig, master=draw_frame)
canvas.get_tk_widget().pack(fill=tk.BOTH, expand=True)

toolbar = NavigationToolbar2Tk(canvas, draw_frame, pack_toolbar=False)
toolbar.pack(side='bottom', fill='x', pady=10, ipady=10)

drawAxis()
FuncManager.addFunc()

def on_closing():
    plt.close('all')
    root.destroy()
    root.quit()
root.protocol('WM_DELETE_WINDOW', on_closing)
root.mainloop()